INSERT INTO public.lk_allowance_rates VALUES ('Salary Index Rate (ຄ່າດັດສະນີ — LAK per Index Point)', 10000.00, 'All Civil Servants', '2026-01-01', NULL, NULL, NULL, 'MoF No. 4904/MOF, 26 Dec 2025', NULL, 'Monetary rate per salary index point. Basic Salary = Grade/Step Index × this rate. Update when MoF issues revised ຄ່າດັດສະນີ circular. Current: 10,000 LAK/index point per MoF 4904/MOF indicative rate.');
INSERT INTO public.lk_allowance_rates VALUES ('Position Allowance - General Staff', 900000.00, 'Technical and general civil servants without administrative position', '2026-01-01', NULL, NULL, NULL, 'MoF No. 4904/MOF, 26 Dec 2025', NULL, 'Professional/technical (general staff) allowance per MoF 4904/MOF. 900,000 LAK/person/month.');
INSERT INTO public.lk_allowance_rates VALUES ('Position Allowance - Section Chief', 1500000.00, 'Section Chief / Type 3 administrative position', '2026-01-01', NULL, NULL, NULL, 'MoF No. 4904/MOF, 26 Dec 2025', NULL, 'Administrative position Type 3 per MoF 4904/MOF. 1,500,000 LAK/person/month.');
INSERT INTO public.lk_allowance_rates VALUES ('Position Allowance - Division Chief', 1900000.00, 'Division Chief / Type 5 administrative position', '2026-01-01', NULL, NULL, NULL, 'MoF No. 4904/MOF, 26 Dec 2025', NULL, 'Administrative position Type 5 per MoF 4904/MOF. 1,900,000 LAK/person/month.');
INSERT INTO public.lk_allowance_rates VALUES ('Position Allowance - Deputy Director', 2300000.00, 'Deputy Director / Type 7 administrative position', '2026-01-01', NULL, NULL, NULL, 'MoF No. 4904/MOF, 26 Dec 2025', NULL, 'Administrative position Type 7 per MoF 4904/MOF. 2,300,000 LAK/person/month.');
INSERT INTO public.lk_allowance_rates VALUES ('Position Allowance - Director', 2500000.00, 'Department Director / Type 8 administrative position', '2026-01-01', NULL, NULL, NULL, 'MoF No. 4904/MOF, 26 Dec 2025', NULL, 'Administrative position Type 8 per MoF 4904/MOF. 2,500,000 LAK/person/month.');
INSERT INTO public.lk_allowance_rates VALUES ('Position Allowance - Deputy Minister', 4000000.00, 'Deputy Minister / Grade 6 Step 2 leadership', '2026-01-01', NULL, NULL, NULL, 'MoF No. 4904/MOF, 26 Dec 2025', NULL, 'Grade 6 Step 2 leadership allowance per MoF 4904/MOF. 4,000,000 LAK/person/month.');
INSERT INTO public.lk_allowance_rates VALUES ('Position Allowance - Minister', 9000000.00, 'Minister / Grade 6 Step 7 highest leadership', '2026-01-01', NULL, NULL, NULL, 'MoF No. 4904/MOF, 26 Dec 2025', NULL, 'Grade 6 Step 7 leadership allowance per MoF 4904/MOF. 9,000,000 LAK/person/month.');
INSERT INTO public.lk_allowance_rates VALUES ('Years of Service Rate — 1 to 5 Years (LAK/year)', 10000.00, 'Staff with 1-5 completed years. Formula: years × 10,000 LAK/year.', '2026-01-01', NULL, NULL, NULL, 'MoF No. 4904/MOF, 26 Dec 2025', NULL, 'Per MoF 4904/MOF Sec 2.2.2. Rate of 10,000 LAK per year for first 5 years of service.');
INSERT INTO public.lk_allowance_rates VALUES ('Years of Service Rate — 6 to 15 Years (LAK/year)', 20000.00, 'Staff with 6-15 completed years. Formula: years × 20,000 LAK/year.', '2026-01-01', NULL, NULL, NULL, 'MoF No. 4904/MOF, 26 Dec 2025', NULL, 'Per MoF 4904/MOF Sec 2.2.2. Rate of 20,000 LAK per year for years 6-15.');
INSERT INTO public.lk_allowance_rates VALUES ('Years of Service Rate — 16 to 25 Years (LAK/year)', 30000.00, 'Staff with 16-25 completed years. Formula: years × 30,000 LAK/year.', '2026-01-01', NULL, NULL, NULL, 'MoF No. 4904/MOF, 26 Dec 2025', NULL, 'Per MoF 4904/MOF Sec 2.2.2. Rate of 30,000 LAK per year for years 16-25.');
INSERT INTO public.lk_allowance_rates VALUES ('Years of Service Rate — 26+ Years (LAK/year)', 40000.00, 'Staff with 26 or more completed years. Formula: years × 40,000 LAK/year.', '2026-01-01', NULL, NULL, NULL, 'MoF No. 4904/MOF, 26 Dec 2025', NULL, 'Per MoF 4904/MOF Sec 2.2.2. Rate of 40,000 LAK per year for 26+ years.');
INSERT INTO public.lk_allowance_rates VALUES ('Teaching Allowance Rate — % of Basic Salary', 0.20, 'Teachers (Field Allowance Type = Teaching). 20% of basic salary (secondary level default). Update for specific levels: Kindergarten/Primary=25%, Secondary=20%, Vocational=15%, Higher Ed=10%.', '2026-01-01', NULL, NULL, NULL, 'MoF No. 4904/MOF, 26 Dec 2025', NULL, 'Per MoF 4904/MOF Sec 2.2.3. Percentage of basic salary. Default: 20% (secondary). Formula in PAYROLL_CALC: Basic Salary × this rate.');
INSERT INTO public.lk_allowance_rates VALUES ('Medical Personnel Allowance', 500000.00, 'Medical personnel providing medical services/treatment and diagnosis (MoH and equivalent).', '2026-01-01', NULL, NULL, NULL, 'MoF No. 4904/MOF, 26 Dec 2025', NULL, 'Per MoF 4904/MOF Sec 4. 500,000 LAK/person/month. Not paid if not performing duty.');
INSERT INTO public.lk_allowance_rates VALUES ('National Assembly (NA) Member Allowance', 1000000.00, 'Elected National Assembly Members.', '2026-01-01', NULL, NULL, NULL, 'MoF No. 4904/MOF, 26 Dec 2025', NULL, 'Per MoF 4904/MOF Sec 5. 1,000,000 LAK/person/month for elected NA members.');
INSERT INTO public.lk_allowance_rates VALUES ('Hardship and Hazardous Jobs Allowance', 1000000.00, 'Staff in designated hazardous roles per Instruction No. 127/MoF dated 14 Feb 1994.', '2026-01-01', NULL, NULL, NULL, 'MoF No. 4904/MOF, 26 Dec 2025', NULL, 'Per MoF 4904/MOF Sec 6. 1,000,000 LAK/person/month.');
INSERT INTO public.lk_allowance_rates VALUES ('Remote / Difficult Area Allowance Rate — % of Basic Salary', 0.25, 'Staff in remote/difficult areas. Default Level 2: 25% of base salary. Level 1=30%, Level 2=25%, Level 3=20% per Decree 292/GoL dated 5 Apr 2021.', '2026-01-01', NULL, NULL, NULL, 'MoF No. 4904/MOF, 26 Dec 2025', NULL, 'Per MoF 4904/MOF Sec 7. Percentage of basic salary. Default Level 2 (25%). Formula: Basic Salary × this rate. Update to 0.30 or 0.20 for other levels.');
INSERT INTO public.lk_allowance_rates VALUES ('Foreign Representative Living Allowance (LAK equivalent)', 20240000.00, 'Staff posted to Lao representative offices abroad. Actual amount in USD per position and area (see MoF 4904/MOF Sec 4 tables).', '2026-01-01', NULL, NULL, NULL, 'MoF No. 4904/MOF, 26 Dec 2025', NULL, 'Per MoF 4904/MOF Sec 4. Area 1 Second Secretary equivalent: USD 1,012 × 20,000 LAK/USD = 20,240,000 LAK. Update with actual USD rate × exchange rate per MFA directive.');
INSERT INTO public.lk_allowance_rates VALUES ('Fuel Benefit — High Ranking Officials (Grade 6)', 0.00, 'Grade 6 leadership officials. Refer to Decree 599/GoL Sep 2021 and MoF Notification 2984/MoF Aug 2024.', '2026-01-01', NULL, NULL, NULL, 'MoF No. 4904/MOF, 26 Dec 2025', NULL, 'Per MoF 4904/MOF Sec 3.1. Follow Decree 599/GoL on State Vehicles. Amount per vehicle policy, not fixed cash.');
INSERT INTO public.lk_allowance_rates VALUES ('Spouse Benefit', 200000.00, 'Married civil servants (Has Spouse = Yes).', '2026-01-01', NULL, NULL, NULL, 'MoF No. 4904/MOF, 26 Dec 2025', NULL, 'Per MoF 4904/MOF Sec 3.2. 200,000 LAK/person/month.');
INSERT INTO public.lk_allowance_rates VALUES ('Child Benefit (per child, max 3)', 200000.00, 'Civil servants with eligible children (max 3).', '2026-01-01', NULL, NULL, NULL, 'MoF No. 4904/MOF, 26 Dec 2025', NULL, 'Per MoF 4904/MOF Sec 3.2. 200,000 LAK/person/month per eligible child. Maximum 3 children.');
INSERT INTO public.lk_allowance_rates VALUES ('SSO Employee Contribution Rate (%)', 5.50, 'All permanent employees — percentage of Basic Salary.', '2026-01-01', NULL, NULL, NULL, 'MoF No. 4904/MOF, 26 Dec 2025', NULL, 'Employee mandatory SSO contribution. Rate per SSO/MLSW decree. Enter as plain number: 5.5 = 5.5%.');
INSERT INTO public.lk_allowance_rates VALUES ('SSO Employer Contribution Rate (%)', 6.00, 'Government (employer) contribution — not deducted from employee salary.', '2026-01-01', NULL, NULL, NULL, 'MoF No. 4904/MOF, 26 Dec 2025', NULL, 'Reference only. Employer SSO contribution borne by government.');
